glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
#if USE_TEXTURE
in vec2 a_uv0;
out vec2 v_uv0;
#endif
void main () {
  vec4 pos = vec4(a_position, 1);
  #if CC_USE_MODEL
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  pos = cc_matViewProj * pos;
  #endif
  #if USE_TEXTURE
  v_uv0 = a_uv0;
  #endif
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
in vec4 v_color;
#if USE_TEXTURE
in vec2 v_uv0;
uniform sampler2D texture;
#endif
uniform PROPERTIES {
  lowp float x;
  lowp float y;
  lowp float z;
  lowp float w;
  lowp float rotated;
  lowp float whratio;
  lowp float iRatio;
};
void main()
{
  vec4 uvOffset = vec4(x, y, z, w);
  float uv0X = (v_uv0.x - uvOffset.x) / (uvOffset.z - uvOffset.x);
  float uv0Y = (v_uv0.y - uvOffset.y) / (uvOffset.w - uvOffset.y);
  vec2 uv0 = rotated > 0.5 ? vec2(uv0Y, 1.0 - uv0X) : vec2(uv0X, uv0Y);
  vec2 center = vec2(0.5, 0.5);
  float radius = iRatio;
  float angle = clamp(1.0 - distance(uv0, center) / radius, 0.0, 1.0);
  angle = angle * angle * iRatio * 15.0;
  uv0 -= 0.5;
  uv0 = mat2(cos(angle), sin(angle), -sin(angle), cos(angle)) * uv0;
  uv0 += 0.5;
  uv0X = uv0.x * (uvOffset.z - uvOffset.x) + uvOffset.x;
  uv0Y = uv0.y * (uvOffset.w - uvOffset.y) + uvOffset.y;
  uv0 = rotated > 0.5 ? vec2(uv0Y, 1.0 - uv0X) : vec2(uv0X, uv0Y);
  vec4 outColor = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
  vec4 texture_tmp = texture(texture, uv0);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, uv0 + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    outColor.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    outColor.a *= texture_tmp.a;
  #else
    outColor *= texture_tmp;
  #endif
  #endif
  gl_FragColor = outColor;
}

